import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Agentic Memory: Learning Unified Long-Term and Short-Term Memory Management for LLM Agents","description":"","frontmatter":{"title":"Agentic Memory: Learning Unified Long-Term and Short-Term Memory Management for LLM Agents","arxiv_id":2601.01885,"authors":"Yi Yu, Liuyi Yao, Yuexiang Xie, et al.","published":"2026-01-05T00:00:00.000Z","source":"https://arxiv.org/abs/2601.01885","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-01-05-agentic-memory-unified-ltm-stm-2601-01885.md","filePath":"research/papers/2026-01-05-agentic-memory-unified-ltm-stm-2601-01885.md","lastUpdated":1779901665000}'),i={name:"research/papers/2026-01-05-agentic-memory-unified-ltm-stm-2601-01885.md"};function n(d,e,l,m,s,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="agentic-memory-learning-unified-long-term-and-short-term-memory-management-for-llm-agents" tabindex="-1">Agentic Memory: Learning Unified Long-Term and Short-Term Memory Management for LLM Agents <a class="header-anchor" href="#agentic-memory-learning-unified-long-term-and-short-term-memory-management-for-llm-agents" aria-label="Permalink to &quot;Agentic Memory: Learning Unified Long-Term and Short-Term Memory Management for LLM Agents&quot;">​</a></h1><p><strong>ArXiv</strong>: 2601.01885 | <strong>Date</strong>: 2026-01-05 (修訂 2026-04-30) | <strong>Authors</strong>: Yi Yu, Liuyi Yao, Yuexiang Xie, et al. | <strong>Category</strong>: cs.CL</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>解決 LLM agent 在有限 context window 內管理擴展推理任務的核心挑戰。現有架構通常「獨立優化長期與短期記憶，再以臨時方式結合」，導致記憶構建碎片化和次優性能。提出 AgeMem 框架，將兩種記憶統一整合到 agent 決策框架中。</p><h2 id="核心創新-agemem" tabindex="-1">核心創新：AgeMem <a class="header-anchor" href="#核心創新-agemem" aria-label="Permalink to &quot;核心創新：AgeMem&quot;">​</a></h2><p><strong>關鍵設計</strong>：將記憶操作暴露為<strong>工具導向行動</strong>，讓 LLM agent 自主決定何時且如何 store、retrieve、update、summarize 或 discard 資訊。</p><h3 id="技術方法" tabindex="-1">技術方法 <a class="header-anchor" href="#技術方法" aria-label="Permalink to &quot;技術方法&quot;">​</a></h3><p>三階段漸進強化學習策略 + step-wise GRPO（Group Relative Policy Optimization）：</p><ul><li>解決記憶操作的稀疏和不連續獎勵挑戰</li><li>端對端學習記憶管理策略（而非依賴預定義 heuristics）</li></ul><h2 id="主要結果" tabindex="-1">主要結果 <a class="header-anchor" href="#主要結果" aria-label="Permalink to &quot;主要結果&quot;">​</a></h2><p>在 5 個長視地平線基準上：</p><ul><li>超越所有現有記憶增強基準</li><li>產生更高品質的長期記憶表示</li><li>更高效的 context 使用</li><li>跨多個 LLM 架構泛化</li></ul><h2 id="與現有方法的對比" tabindex="-1">與現有方法的對比 <a class="header-anchor" href="#與現有方法的對比" aria-label="Permalink to &quot;與現有方法的對比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方法</th><th>短期記憶</th><th>長期記憶</th><th>整合方式</th></tr></thead><tbody><tr><td>傳統方法</td><td>靜態 STM + 觸發式 LTM</td><td>靜態 STM + agent-based LTM</td><td>獨立優化後臨時組合</td></tr><tr><td>AgeMem</td><td>工具驅動統一管理</td><td>工具驅動統一管理</td><td>端對端聯合優化</td></tr></tbody></table><h2 id="與-automode-概念的關係" tabindex="-1">與 AutoMode 概念的關係 <a class="header-anchor" href="#與-automode-概念的關係" aria-label="Permalink to &quot;與 AutoMode 概念的關係&quot;">​</a></h2><p>與 <code>2026-05-13-useful-memories-faulty-llm</code> 中的 AutoMode 設計理念一致：</p><ul><li>讓 agent 自主決定 Retain/Delete/Consolidate（而非強制整合）</li><li>AgeMem 進一步通過 RL 優化此自主決策能力</li></ul><h2 id="代碼" tabindex="-1">代碼 <a class="header-anchor" href="#代碼" aria-label="Permalink to &quot;代碼&quot;">​</a></h2><p>公開可用，支持可重現性。</p><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Memory Architecture</strong> — 首個通過強化學習端對端統一長短期記憶管理的框架，為 AutoMode 概念提供了 RL 優化路徑。</p>',21)])])}const c=t(i,[["render",n]]);export{u as __pageData,c as default};
